def parse_fasta(filepath):
    """解析FASTA文件，返回 {序列ID: 序列} 字典"""
    sequences = {}
    try:
        with open(filepath) as f:
            current_id = None
            for line in f:
                line = line.strip()
                if line.startswith('>'):
                    current_id = line[1:].split()[0]
                    sequences[current_id] = ''
                else:
                    sequences[current_id] += line
    except FileNotFoundError:
        print(f"错误: 文件 {filepath} 不存在")
        return None
    except Exception as e:
        print(f"解析出错: {e}")
        return None
    else:
        print(f"成功加载 {len(sequences)} 条序列")
        return sequences

# 使用
seqs = parse_fasta("genome.fa")
if seqs:
    for seq_id, seq in list(seqs.items())[:3]:
